parameters.jsCode:
// Seller-Stammdaten (einmalig pflegen, kommen nicht aus der DB)
// Anpassen!
const SELLER = {
  name:            "Jasper Büsch",
  business_name:   "Buschi Creations",
  street:          "Musterstraße 1",
  zip:             "80331",
  city:            "München",
  country:         "Deutschland",
  email:           "shop@buschi-creations.de",
  iban:            "DE89 3704 0044 0532 0130 00",
  bank_name:       "Commerzbank",
  tax_id:          "123/456/78901",
  kleinunternehmer: true,
};

const o = $input.item.json;
const items = JSON.parse(o.items_json ?? '[]');

// Artikel für API formatieren
const lineItems = items.map((it, i) => ({
  pos:        i + 1,
  description: it.title,
  quantity:    it.quantity,
  unit_price:  it.price,
  total:       it.price * it.quantity,
}));

const buyer = {
  name:    o.buyer_name,
  street:  o.buyer_street,
  zip:     o.buyer_zip,
  city:    o.buyer_city,
  country: o.buyer_country,
};

const invoiceDate = new Date(o.order_date)
  .toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' });

return {
  json: {
    // Rechnungsrequest
    invoice_request: {
      invoice_number: o.invoice_number,
      invoice_date:   invoiceDate,
      order_id:       o.order_id,
      seller:         SELLER,
      buyer,
      items:          lineItems,
      subtotal:       o.subtotal,
      shipping_cost:  o.shipping_cost,
      total:          o.total,
      currency:       o.currency,
      payment_note:   "Bereits bezahlt via Etsy Payments",
    },
    // Lieferscheinrequest
    delivery_request: {
      delivery_number: "LS-" + o.invoice_number,
      date:            invoiceDate,
      order_id:        o.order_id,
      seller:          SELLER,
      buyer,
      items:           lineItems,
      tracking_number: o.tracking_number,
      carrier:         o.carrier,
    },
    order_id: o.order_id,
  }
};

